1. Create utils/imageCache.ts:
   export class ImageLRUCache {
     private items: ImageFile[] = [];
     private config = { maxItems: 50, maxBytes: 100 * 1024 * 1024 };
     private currentBytes = 0;

     add(image: ImageFile): void {
       const imageSize = Math.floor(image.base64.length * 0.75);
       this.items.unshift(image); // Most recent first
       this.currentBytes += imageSize;
       this.evictIfNeeded(); // Remove oldest when limits exceeded
     }

     private evictIfNeeded(): void {
       while (this.items.length > maxItems || this.currentBytes > maxBytes) {
         const evicted = this.items.pop();
         this.currentBytes -= Math.floor(evicted.base64.length * 0.75);
       }
     }

     getAll(): ImageFile[] { return this.items; }
     clear(): void { this.items = []; this.currentBytes = 0; }
     getMetrics() { return { itemCount, totalBytes, totalMB }; }
   }
